 1	import * as React from 'react';
 2	import { ButtonBar } from '@odf/shared/generic/ButtonBar';
 3	import { CommonModalProps } from '@odf/shared/modals';
 4	import { S3Commands } from '@odf/shared/s3';
 5	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 6	import {
 7	  Modal,
 8	  ModalVariant,
 9	  Button,
10	  ButtonVariant,
11	} from '@patternfly/react-core';
12	
13	type SaveBucketPolicyModalModalProps = {
14	  bucketName: string;
15	  s3Client: S3Commands;
16	  triggerRefresh: () => void;
17	  policy: string;
18	  setSuccess: React.Dispatch<React.SetStateAction<boolean>>;
19	};
20	
21	const SaveBucketPolicyModal: React.FC<
22	  CommonModalProps<SaveBucketPolicyModalModalProps>
23	> = ({
24	  closeModal,
25	  isOpen,
26	  extraProps: { bucketName, s3Client, triggerRefresh, policy, setSuccess },
27	}) => {
28	  const { t } = useCustomTranslation();
29	
30	  const [inProgress, setInProgress] = React.useState<boolean>(false);
31	  const [error, setError] = React.useState<Error>();
32	
33	  const onSave = async (event) => {
34	    event.preventDefault();
35	    setInProgress(true);
36	
37	    try {
38	      await s3Client.setBucketPolicy({ Bucket: bucketName, Policy: policy });
39	
40	      setInProgress(false);
41	      closeModal();
42	      setSuccess(true);
43	      triggerRefresh();
44	    } catch (err) {
45	      setInProgress(false);
46	      setError(err);
47	    }
48	  };
49	
50	  return (
51	    <Modal
52	      title={t('Confirm save changes?')}
53	      titleIconVariant="warning"
54	      isOpen={isOpen}
55	      onClose={closeModal}
56	      description={
57	        <div className="text-muted">
58	          {t(
59	            'This action will overwrite the existing configuration, and any updates will immediately affect access permissions for users and applications. Review your changes carefully before proceeding.'
60	          )}
61	        </div>
62	      }
63	      variant={ModalVariant.medium}
64	      actions={[
65	        <ButtonBar
66	          inProgress={inProgress}
67	          errorMessage={error?.message || JSON.stringify(error)}
68	        >
69	          <span>
70	            <Button
71	              variant={ButtonVariant.primary}
72	              onClick={onSave}
73	              isDisabled={!!error || inProgress}
74	              className="pf-v6-u-mr-xs"
75	            >
76	              {t('Update policy')}
77	            </Button>
78	            <Button
79	              variant={ButtonVariant.link}
80	              onClick={closeModal}
81	              className="pf-v6-u-ml-xs"
82	            >
83	              {t('Cancel')}
84	            </Button>
85	          </span>
86	        </ButtonBar>,
87	      ]}
88	    >
89	      {' '}
90	    </Modal>
91	  );
92	};
93	
94	export default SaveBucketPolicyModal;

